def _download_blob(bucket: str, name: str, generation: str = "") -> Dict[str, Any]:
    client = _get_storage()
    b = client.bucket(bucket)
    if generation:
        blob = b.blob(name, generation=generation)
    else:
        blob = b.blob(name)

    blob.reload()

    size = int(getattr(blob, "size", 0) or 0)
